import React, { useEffect, useState } from "react";
import axios from "axios";
import "bootstrap/dist/css/bootstrap.min.css";
import Pagination from "../components/Pagination";
import { FaHistory, FaSync, FaFileInvoiceDollar } from "react-icons/fa";

// Configuración de URL dinámica
const API_URL = process.env.REACT_APP_API_URL || "http://localhost:5000";

export default function VentasHistorial() {
  const [ventas, setVentas] = useState([]);
  const [loading, setLoading] = useState(true);
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 10; 

  useEffect(() => {
    cargarHistorial();
  }, []);

  const cargarHistorial = async () => {
    try {
      setLoading(true);
      // Petición al backend de MongoDB
      const res = await axios.get(`${API_URL}/api/ventas/historial`);
      setVentas(res.data);
    } catch (error) {
      console.error("❌ Error al cargar historial:", error);
    } finally {
      setLoading(false);
    }
  };

  // Lógica de Paginación
  const indexLast = currentPage * itemsPerPage;
  const indexFirst = indexLast - itemsPerPage;
  const ventasMostradas = ventas.slice(indexFirst, indexLast);

  if (loading) {
    return (
      <div className="container mt-5 text-center">
        <div className="spinner-border text-primary" role="status"></div>
        <p className="mt-2 fw-bold text-secondary">Cargando historial de ventas...</p>
      </div>
    );
  }

  return (
    <div className="container-fluid p-4 pb-5">
      <div className="d-flex justify-content-between align-items-center mb-4">
        <h3 className="fw-bold text-dark mb-0">
          <FaHistory className="me-2 text-primary" /> Historial de Ventas
        </h3>
        <button className="btn btn-primary shadow-sm d-flex align-items-center" onClick={cargarHistorial}>
          <FaSync className="me-2" /> Actualizar Datos
        </button>
      </div>

      <div className="card shadow-sm border-0 overflow-hidden" style={{ borderRadius: "15px" }}>
        <div className="table-responsive">
          <table className="table table-hover align-middle mb-0">
            <thead className="bg-dark text-white">
              <tr className="text-center">
                <th className="py-3">Factura #</th>
                <th className="py-3">Fecha y Hora</th>
                <th className="py-3 text-start ps-4">Cliente</th>
                <th className="py-3">Subtotal</th>
                <th className="py-3">IVA (13%)</th>
                <th className="py-3">Total</th>
              </tr>
            </thead>
            <tbody>
              {ventasMostradas.length > 0 ? (
                ventasMostradas.map((v) => (
                  <tr key={v._id} className="text-center border-bottom">
                    <td className="fw-bold text-primary">
                      <FaFileInvoiceDollar className="me-2 text-muted opacity-50" />
                      {/* En MongoDB usamos NumeroSecuencia o los últimos 6 del _id como respaldo */}
                      {(v.numeroSecuencia || v._id.slice(-6)).toString().toUpperCase()}
                    </td>
                    <td className="text-muted small">
                      {new Date(v.fecha || v.createdAt).toLocaleString('es-SV')}
                    </td>
                    <td className="text-start ps-4 fw-semibold text-dark">
                      {v.cliente ? `${v.cliente.nombre} ${v.cliente.apellido}` : "Cliente General"}
                    </td>
                    <td className="text-secondary">${Number(v.subtotal || 0).toFixed(2)}</td>
                    <td className="text-secondary">${Number(v.iva || 0).toFixed(2)}</td>
                    <td className="fw-bold text-success fs-6">
                        ${Number(v.total || 0).toFixed(2)}
                    </td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan="6" className="py-5 text-center text-muted">
                    <div className="mb-2 fs-1 opacity-25">📉</div>
                    <p className="mb-0">No se encontraron ventas registradas.</p>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* 📄 CONTROLES DE PAGINACIÓN */}
      {ventas.length > itemsPerPage && (
        <div className="d-flex justify-content-center mt-4">
          <Pagination
            totalItems={ventas.length}
            itemsPerPage={itemsPerPage}
            currentPage={currentPage}
            onPageChange={setCurrentPage}
          />
        </div>
      )}
    </div>
  );
}
